// Calendar.js
import React from 'react';
import FullCalendar from '@fullcalendar/react';
import dayGridPlugin from '@fullcalendar/daygrid';
import interactionPlugin from '@fullcalendar/interaction'; // Enables interaction like clicking
import axios from 'axios';

function Calendar() {
  // Define the calendar events state to be filled by an API call
  const [events, setEvents] = React.useState([]);

  // Fetch events from your backend when the component mounts
  React.useEffect(() => {
    axios.get('http://localhost:3001/events')
      .then((response) => {
        console.log('Fetched events:', response.data);
        setEvents(response.data);
      })
      .catch((error) => {
        console.error('Error fetching events:', error);
      });
  }, []);

  return (
    <div>
      <h2>Event Calendar</h2>
      <FullCalendar
        plugins={[dayGridPlugin, interactionPlugin]}
        initialView="dayGridMonth"
        events={events} // Pass the fetched events to FullCalendar
        eventClick={(info) => {
          info.jsEvent.preventDefault();
          if (info.event.url) {
            window.open(info.event.url);
          }
        }}
      />
    </div>
  );
}

export default Calendar;
